(118,0,'2020-03-01 00:00:00','2020-03-01 00:00:00','Updated: May 14, 2020<br />\n<br />\n#pro-gallery-3ogev-not-scoped .gallery-item-container { opacity: 0 }<br />\n      #pro-gallery-3ogev-not-scoped .gallery-item-hover::before { background: transparent !important}try {<br />\n            window.requestAnimationFrame(function() {<br />\n              <br />\n  <br />\n      var ele = document.getElementById(\'pro-gallery-3ogev-not-scoped\');<br />\n      var pgMeasures = ele.getBoundingClientRect();<br />\n      var options = (() =&gt; \"gallerySizeType:px|enableInfiniteScroll:true|titlePlacement:SHOW_ON_HOVER|hasThumbnails:false|imageMargin:20|galleryLayout:6|isVertical:true|gallerySizePx:300|cubeType:fill|galleryThumbnailsAlignment:none\")(ele);<br />\n      var width = pgMeasures.width;<br />\n      var height = pgMeasures.height;<br />\n<br />\n      var isIOS = /iPad|iPhone|iPod/.test(navigator?.userAgent);<br />\n      if(isIOS) {<br />\n        width = width;<br />\n        width = width;<br />\n        height = height;<br />\n        height = height;<br />\n      } else {<br />\n        width = width;<br />\n        width = width;<br />\n        height = height;<br />\n        height = height;<br />\n      }<br />\n<br />\n      pgMeasures = { top: pgMeasures.top, width, height };<br />\n<br />\n  var isVertical = options.includes(\'layoutParams_structure_scrollDirection:\"VERTICAL\"\');<br />\n  var layoutFixerUrl =  \'/_serverless/pro-gallery-css-v4-server/layoutCss?ver=2&amp;id=3ogev-not-scoped&amp;items=3523_2048_1362&amp;container=\' + pgMeasures.top + \'_\' + pgMeasures.width + \'_\' + pgMeasures.height + \'_\' + window.innerHeight + \'&amp;options=\' + options;<br />\n  document.getElementById(\'layout-fixer-style-3ogev-not-scoped\').setAttribute(\'href\', encodeURI(layoutFixerUrl));<br />\n});<br />\n<br />\n  <br />\n        } catch (e) {<br />\n          console.warn(\'Cannot set layoutFixer css\', e);<br />\n        }There is some innate cool factor to the secret, whatever that secret may be. Which is why, as long as you promise not to tell who told you, here is the best kept speakeasy club in Hong Kong.<br />\n<br />\nLittle Su, conjures all the cliches of a mysterious and scandalous upscale lounge club.<br />\n<br />\nTucked behind a casual wall entrance within another club – Play. Make your way past the Play club entrance and coming up the escalators. You’ll find yourself in the dance club. Instead, look for a red lamp-bulb. And push the wall underneath it. Make your way through a door that looks like it leads into a closet. Little Su awaits.<br />\n<br />\nThe best vibe in town is often the hardest to find, a treat only for those who put in the effort.<br />\n<br />\n#pro-gallery-a47in-not-scoped .gallery-item-container { opacity: 0 }<br />\n      #pro-gallery-a47in-not-scoped .gallery-item-hover::before { background: transparent !important}try {<br />\n            window.requestAnimationFrame(function() {<br />\n              <br />\n  <br />\n      var ele = document.getElementById(\'pro-gallery-a47in-not-scoped\');<br />\n      var pgMeasures = ele.getBoundingClientRect();<br />\n      var options = (() =&gt; \"gallerySizeType:px|enableInfiniteScroll:true|titlePlacement:SHOW_ON_HOVER|gridStyle:1|imageMargin:10|galleryLayout:2|isVertical:false|numberOfImagesPerRow:2|gallerySizePx:300|cubeRatio:1|cubeType:fill|galleryThumbnailsAlignment:bottom|thumbnailSpacings:0\")(ele);<br />\n      var width = pgMeasures.width;<br />\n      var height = pgMeasures.height;<br />\n<br />\n      var isIOS = /iPad|iPhone|iPod/.test(navigator?.userAgent);<br />\n      if(isIOS) {<br />\n        width = width;<br />\n        width = width;<br />\n        height = height;<br />\n        height = height;<br />\n      } else {<br />\n        width = width;<br />\n        width = width;<br />\n        height = height;<br />\n        height = height;<br />\n      }<br />\n<br />\n      pgMeasures = { top: pgMeasures.top, width, height };<br />\n<br />\n  var isVertical = options.includes(\'layoutParams_structure_scrollDirection:\"VERTICAL\"\');<br />\n  var layoutFixerUrl =  \'/_serverless/pro-gallery-css-v4-server/layoutCss?ver=2&amp;id=a47in-not-scoped&amp;items=3657_1785_1758|3746_1788_1752|3373_1788_1755|3523_1782_1752|3558_1785_1755|3394_1692_1362|3573_1428_1755|3596_1791_1722&amp;container=\' + pgMeasures.top + \'_\' + pgMeasures.width + \'_\' + pgMeasures.height + \'_\' + window.innerHeight + \'&amp;options=\' + options;<br />\n  document.getElementById(\'layout-fixer-style-a47in-not-scoped\').setAttribute(\'href\', encodeURI(layoutFixerUrl));<br />\n});<br />\n<br />\n  <br />\n        } catch (e) {<br />\n          console.warn(\'Cannot set layoutFixer css\', e);<br />\n        }*Photos from Instagram and Client&#x27;s website','Little Su ・紅雙喜','','publish','open','open','','little-su-%e3%83%bb%e7%b4%85%e9%9b%99%e5%96%9c','','','2020-03-01 00:00:00','2020-03-01 00:00:00','',0,'http://113.253.77.204:8080/little-su-%e3%83%bb%e7%b4%85%e9%9b%99%e5%96%9c/',0,'post','',0),
